const raw = $input.first().json.response;
let memo;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  memo = JSON.parse(jsonMatch[0]);
} catch(e) {
  memo = { parse_error: true, raw_response: raw };
}
memo.version = 'v1';
memo.source = 'demo_call';
return [{ json: { memo, account_id: memo.account_id } }];

const memo = $input.first().json.memo;
const content = JSON.stringify(memo, null, 2);

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(content, 'utf-8'),
  'account_memo_v1.json',
  'application/json'
);

return [{ json: $input.first().json, binary: { memoFile: binaryData } }];

const spec = $input.first().json.spec;
const content = JSON.stringify(spec, null, 2);

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(content, 'utf-8'),
  'agent_spec_v1.json',
  'application/json'
);

return [{ json: $input.first().json, binary: { specFile: binaryData } }];

const fs = require('fs');
const content = fs.readFileSync('/data/transcripts/demo/demo_001.txt', 'utf8').replace(/^\uFEFF/, '').trim();
return [{ json: { account_id: 'demo_001', transcript: content, filename: 'demo_001.txt' } }];
